import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface PerformanceMetrics {
  queryTimeP99: number;
  activeConnections: number;
  slowQueries: number;
}

interface DatabasePerformanceData {
  performanceMetrics: PerformanceMetrics;
  queryTimeTrend: number[];
  connectionTrend: number[];
  slowQueryTrend: number[];
}

export default function Widget() {
  const data = response.data as DatabasePerformanceData;
  const { performanceMetrics, queryTimeTrend } = data;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: 'rgba(26, 32, 44, 0.75)', backdropFilter: 'blur(10px)', color: '#F5F7FA' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Database Performance
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#F5F7FA', mb: 1 }}>
              Query Time P99: {performanceMetrics.queryTimeP99}ms
            </Typography>
            <Stack direction="row" spacing={2}>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Active Connections
                </Typography>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#F5F7FA' }}>
                  {performanceMetrics.activeConnections}
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Slow Queries
                </Typography>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#F5F7FA' }}>
                  {performanceMetrics.slowQueries}
                </Typography>
              </Box>
            </Stack>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: queryTimeTrend,
                color: '#F56565',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: queryTimeTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
